#include<bits/stdc++.h>
using namespace std;
int flag[150][150];
bool vis[150][150];
int n,m,t;
struct node
{
    int x,y;
    node():x(0),y(0){}
}match[150][150];
int dx[8]={1,-1,2,-2,1,-1,2,-2};
int dy[8]={2,2,1,1,-2,-2,-1,-1};
bool km(int x,int y)
{
    for(int i=0;i<8;i++)
    {
        int xx=x+dx[i];
        int yy=y+dy[i];
        if(xx<1||xx>n||yy<1||yy>m)
        {
            continue;
        }
        if(!vis[xx][yy]&&!flag[xx][yy])
        {
            vis[xx][yy]=1;
            if(match[xx][yy].x==0||km(match[xx][yy].x,match[xx][yy].y))
            {
                match[xx][yy].x=x;
                match[xx][yy].y=y;
                return true;
            }
        }
    }
    return false;
}
int main()
{
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=t;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        flag[x][y]=1;
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            if((i+j)%2==0||flag[i][j])
            {
                continue;
            }
            memset(vis,0,sizeof(vis));
            ans+=km(i,j);
        }
    }
    printf("%d",n*m-t-ans);
    return 0;
}
